insert into public.questions (id, category, question, options, correct, explanation) values
(1,'Road Signs','What does a red circular road sign indicate?','["A warning to drivers","A prohibition or restriction","A mandatory instruction","An informational guide"]',1,'Red circular signs in Singapore indicate prohibitions or restrictions, such as ''No Entry'' or speed limits.'),
(2,'Road Signs','A triangular road sign with a red border is used to indicate:','["A mandatory instruction","A prohibition","A warning of a hazard ahead","A direction to follow"]',2,'Triangular signs with red borders are warning signs, alerting drivers to potential hazards ahead such as bends, crossings, or road works.'),
(3,'Road Signs','What does a blue rectangular road sign typically convey in Singapore?','["Danger ahead","Prohibition","Informational or directional guidance","Speed restriction"]',2,'Blue rectangular signs provide information or directional guidance, such as highway exit signs or parking area indicators.'),
(4,'Road Signs','A ''Give Way'' sign is shaped like:','["A red circle","An inverted red triangle","A blue square","A yellow diamond"]',1,'The ''Give Way'' sign is an inverted triangle (point facing down) with a red border, requiring drivers to yield to oncoming traffic.'),
(5,'Road Signs','What does the ''No Entry'' sign look like?','["A red triangle with an exclamation mark","A blue circle with a white arrow","A red circle with a white horizontal bar","A yellow diamond with a black cross"]',2,'The ''No Entry'' sign is a red circle with a white horizontal bar, prohibiting vehicles from entering that road or lane.'),
(6,'Speed Limits','What is the default speed limit on expressways in Singapore?','["70 km/h","80 km/h","90 km/h","110 km/h"]',2,'The default speed limit on Singapore expressways is 90 km/h unless otherwise posted.'),
(7,'Speed Limits','What is the default speed limit on roads in Singapore where no speed limit sign is posted?','["40 km/h","50 km/h","60 km/h","70 km/h"]',1,'Where no speed limit sign is displayed, the default speed limit on Singapore roads is 50 km/h.'),
(8,'Speed Limits','In a school zone during school hours, what is the speed limit in Singapore?','["15 km/h","25 km/h","40 km/h","50 km/h"]',2,'In designated school zones during school hours, the speed limit is reduced to 40 km/h to protect children.'),
(9,'Speed Limits','A newly licensed driver (Class 3 probationer) must not exceed what speed limit?','["60 km/h","70 km/h","80 km/h","90 km/h"]',1,'Probationary licence holders in Singapore are restricted to a maximum speed of 70 km/h regardless of the posted speed limit.'),
(10,'Speed Limits','What is the maximum speed limit allowed on Singapore expressways?','["80 km/h","90 km/h","110 km/h","130 km/h"]',1,'The maximum speed limit on Singapore expressways is 90 km/h unless a higher limit is specifically posted.'),
(11,'Right of Way','At an uncontrolled intersection where two roads meet, which vehicle has the right of way?','["The vehicle on the left","The vehicle on the right","The larger vehicle","The vehicle that arrived first"]',1,'At an uncontrolled intersection, you must give way to traffic approaching from your right.'),
(12,'Right of Way','When must you give way to pedestrians in Singapore?','["Only at signalised crossings when the light is green for pedestrians","Only at zebra crossings","At both zebra crossings and signalised pedestrian crossings","Only when a traffic officer is present"]',2,'Drivers must give way to pedestrians at both zebra crossings and signalised pedestrian crossings when it is safe for them to cross.'),
(13,'Right of Way','When turning right at a junction, you must give way to:','["Vehicles turning left only","Oncoming vehicles travelling straight ahead","Vehicles behind you","Nothing — turning right has priority"]',1,'When turning right, you must give way to oncoming vehicles travelling straight or turning left, as they have the right of way.'),
(14,'Right of Way','A vehicle joining a major road from a minor road must:','["Proceed quickly before traffic arrives","Sound the horn to signal intention","Give way to all traffic on the major road","Flash headlights and proceed"]',2,'Traffic on the minor road must always give way to traffic already travelling on the major road before joining.'),
(15,'Right of Way','At a roundabout in Singapore, who has priority?','["Vehicles entering the roundabout","Vehicles already circulating inside the roundabout","The largest vehicle","Vehicles on the right of the roundabout"]',1,'Vehicles already inside the roundabout have priority. Vehicles entering must give way to circulating traffic.'),
(16,'Traffic Signals','What must you do when a traffic light turns amber?','["Speed up to clear the junction","Stop if it is safe to do so","Continue at the same speed","Sound your horn and proceed"]',1,'An amber light means stop if it is safe to do so. You should only proceed if stopping would be unsafe.'),
(17,'Traffic Signals','A green arrow traffic signal allows you to:','["Proceed in any direction","Proceed only in the direction of the arrow, giving way to other traffic","Stop and wait","Turn in the direction of the arrow without giving way to anyone"]',1,'A green arrow (filter arrow) allows you to move in that specific direction but you must still give way to pedestrians and other traffic.'),
(18,'Traffic Signals','What does a flashing amber traffic light indicate?','["Stop immediately","Proceed with caution","The light is about to change to red","Road works ahead"]',1,'A flashing amber light means proceed with caution, being alert to cross traffic and pedestrians.'),
(19,'Traffic Signals','When a traffic light is not working at an intersection, what rule applies?','["The road becomes a free-for-all","Treat it as a ''Give Way'' junction","Treat it as a ''Stop'' sign junction","Treat it as an uncontrolled intersection and give way to traffic from the right"]',3,'When traffic signals are not working, drivers should treat the junction as an uncontrolled intersection and give way to traffic from the right.'),
(20,'Traffic Signals','You are approaching a green traffic light at a junction. What should you do?','["Accelerate to pass before it changes","Proceed but be prepared to stop if it changes","Stop and check for cross-traffic first","Sound your horn and proceed at speed"]',1,'Even on a green light, you should proceed while being alert — never speed up to beat a potential change.'),
(21,'Safe Following Distance','What is the recommended safe following distance rule in Singapore?','["1-second rule","2-second rule","3-second rule","4-second rule"]',1,'The 2-second rule is recommended: maintain at least a 2-second gap behind the vehicle in front under normal conditions.'),
(22,'Safe Following Distance','In wet weather, how should you adjust your following distance?','["Keep the same distance","Reduce it to brake faster","Double it to at least 4 seconds","Follow 1 metre per 10 km/h of speed"]',2,'In wet conditions, braking distances increase significantly. You should at least double your following distance to a minimum of 4 seconds.'),
(23,'Safe Following Distance','Tailgating is dangerous primarily because:','["It annoys other drivers","It reduces your reaction time and braking distance","It increases fuel consumption","It is only illegal on expressways"]',1,'Tailgating leaves insufficient distance to react and brake safely if the vehicle ahead stops suddenly.'),
(24,'Safe Following Distance','When following a large vehicle like a bus or truck, you should maintain a larger gap because:','["Large vehicles have right of way","Large vehicles obstruct your forward visibility","It is a legal requirement in Singapore","Large vehicles travel faster"]',1,'Large vehicles block your view of the road ahead. A larger gap improves your visibility and reaction time.'),
(25,'Safe Following Distance','At 80 km/h on a dry road, approximately what is the total stopping distance (reaction + braking)?','["20 metres","40 metres","75 metres","100 metres"]',2,'At 80 km/h, the total stopping distance is approximately 75 metres on a dry road.'),
(26,'Lane Discipline','On a multi-lane expressway, which lane should you normally use for driving?','["The rightmost lane","The leftmost lane (Lane 1)","Any lane you prefer","The middle lane"]',1,'In Singapore, you should keep left unless overtaking. The leftmost lane is for normal driving.'),
(27,'Lane Discipline','When is it legal to overtake on the left in Singapore?','["Never","When the vehicle ahead is turning right and there is a clear lane to its left","Whenever there is space","Only on expressways"]',1,'Overtaking on the left is permitted when the vehicle ahead is turning right and there is a safe lane to its left for you to pass.'),
(28,'Lane Discipline','What must you do before changing lanes?','["Sound your horn","Flash your headlights","Check mirrors, signal, check blind spot, then move","Brake to slow down first"]',2,'The safe lane-change procedure is: check mirrors, signal your intention, check the blind spot, and only then make the lane change.'),
(29,'Lane Discipline','Box junctions (yellow criss-cross markings) at intersections mean:','["You may stop here to wait for a gap","Do not enter unless your exit is clear","Park only in emergencies","Bus-only zone"]',1,'You must not enter a box junction unless your exit road is clear so that you do not block cross traffic.'),
(30,'Lane Discipline','What does a continuous white line separating lanes indicate?','["You may change lanes freely","Lane changing is prohibited across this line","Overtaking is allowed here","The lane is for buses only"]',1,'A continuous (solid) white lane line must not be crossed for overtaking or lane changing.'),
(31,'Parking Rules','What does a double yellow kerb marking indicate in Singapore?','["Short-term parking allowed","Parking prohibited at all times","Loading and unloading only","Parking allowed after 6 pm"]',1,'A double yellow line along the kerb means parking is prohibited at all times, including Sundays and public holidays.'),
(32,'Parking Rules','A single yellow kerb line in Singapore means:','["No parking at any time","No parking during restricted hours shown on a nearby sign","Parking for motorcycles only","Free parking zone"]',1,'A single yellow line means parking is restricted during times displayed on a nearby sign. Outside those hours, parking is generally permitted.'),
(33,'Parking Rules','Parking within how many metres of a fire hydrant is prohibited?','["1 metre","3 metres","5 metres","10 metres"]',1,'Vehicles must not be parked within 3 metres of a fire hydrant to ensure emergency access is not obstructed.'),
(34,'Parking Rules','In Singapore, where is it illegal to park even briefly?','["In front of a private driveway","On a public road with no yellow lines after 10 pm","In a carpark with a parking coupon","In a loading bay outside restricted hours"]',0,'Parking in front of a private driveway is illegal as it obstructs access for the resident or property owner.'),
(35,'Parking Rules','What is the purpose of an Electronic Parking System (EPS) in Singapore?','["To control traffic flow","To automatically deduct parking charges from a stored-value card","To issue parking fines electronically","To reserve parking spaces in advance"]',1,'EPS uses an In-vehicle Unit (IU) to automatically deduct parking charges from a CashCard or via NETS when entering and exiting a carpark.'),
(36,'Road Signs','What does a sign showing a red circle with a number (e.g. ''60'') inside mean?','["Minimum speed of 60 km/h","Maximum speed limit of 60 km/h","Speed recommended at 60 km/h","Road ahead has 60 metre visibility"]',1,'A red circle enclosing a number is a maximum speed limit sign. Driving above that speed is an offence.'),
(37,'Road Signs','What does a ''Stop'' sign (octagonal red sign) require you to do?','["Slow down and proceed if clear","Give way to traffic from the right only","Come to a complete stop and give way before proceeding","Stop only if traffic is visible"]',2,'A ''Stop'' sign requires a complete stop regardless of whether traffic is visible. You must only proceed when it is safe.'),
(38,'Traffic Signals','What does a pedestrian signal showing a flashing green man mean?','["Pedestrians may start crossing","Pedestrians should hurry as the signal is about to change to red","Vehicles may proceed","Cyclists may cross"]',1,'A flashing green man means pedestrians already crossing should hurry as the signal is about to change.'),
(39,'Safe Following Distance','The ''thinking distance'' (reaction distance) at 60 km/h for an average driver is approximately:','["5 metres","10 metres","17 metres","25 metres"]',2,'At 60 km/h, an average reaction time of about 1 second means a thinking/reaction distance of approximately 17 metres.'),
(40,'Lane Discipline','When may you use the emergency lane (hard shoulder) on an expressway?','["When traffic is heavy","To overtake slow vehicles","Only in a genuine emergency or breakdown","To make a U-turn"]',2,'The emergency lane must only be used in a genuine emergency or breakdown. Using it for any other purpose is an offence.'),
(41,'Right of Way','When emerging from a car park onto a public road, you must:','["Sound horn and proceed quickly","Give way to all pedestrians and vehicles on the public road","Wait for a traffic officer to direct you","Flash headlights and merge"]',1,'When exiting a car park or private premises, you must give way to all traffic and pedestrians on the public road.'),
(42,'Road Signs','A sign with a white ''P'' on a blue background indicates:','["No parking","Parking permitted","Police station ahead","Pay-and-display parking only"]',1,'A white ''P'' on a blue background is the standard parking sign indicating that parking is permitted in that area.'),
(43,'Speed Limits','What offence is committed if a driver travels at 70 km/h in a 50 km/h zone?','["No offence — 20 km/h above is within tolerance","Speeding by more than 20 km/h — attracts higher penalties","Only a warning","Offence only if an accident occurs"]',1,'Exceeding the speed limit by more than 20 km/h is considered a serious speeding offence in Singapore and attracts heavier fines and demerit points.'),
(44,'Lane Discipline','What does a broken (dashed) white lane line mean?','["No lane changing allowed","Lane changing is permitted when safe","Bus lane boundary","Bicycle lane boundary"]',1,'A broken white lane line indicates that lane changing is permitted, provided it is safe to do so.'),
(45,'Parking Rules','Parking on a pedestrian crossing or within how many metres before it is prohibited?','["3 metres","5 metres","9 metres","15 metres"]',2,'Parking within 9 metres before a pedestrian crossing and on the crossing itself is prohibited.'),
(46,'Right of Way','An ambulance with its siren and lights activated is approaching. You should:','["Speed up to clear the road faster","Pull over to the left and stop to let it pass","Maintain your speed and lane","Sound your horn in response"]',1,'When an emergency vehicle with lights and siren is approaching, pull over to the left and stop to allow it to pass safely.'),
(47,'Traffic Signals','A red traffic light with a green left-turn arrow lit simultaneously means:','["All traffic may proceed","Only vehicles turning left may proceed","Only vehicles going straight may proceed","All traffic must stop"]',1,'When a red light is accompanied by a green left-turn filter arrow, only vehicles turning left may proceed.'),
(48,'Road Signs','What does a sign showing two arrows pointing in opposite directions indicate?','["One-way road ahead","Two-way traffic ahead","Road narrows ahead","Overtaking prohibited"]',1,'The two-way traffic sign warns drivers that the road ahead carries traffic in both directions.'),
(49,'Safe Following Distance','What is the key danger of driving too close to the vehicle in front when on a motorway?','["Increased fuel consumption","Higher wind resistance","Insufficient distance to brake safely if the front vehicle stops suddenly","Risk of aquaplaning"]',2,'At high speeds, a tailgating driver may have insufficient distance to brake before colliding with a vehicle that stops suddenly.'),
(50,'Parking Rules','Which of the following is NOT a valid parking coupon denomination used in Singapore?','["50 cents","$1.00","$2.00","$5.00"]',3,'Singapore coupon parking denominations are 50 cents, $1.00, and $2.00. There is no $5.00 coupon denomination.')
